import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const MONTH_NAMES = ["January","February","March","April","May","June","July","August","September","October","November","December"];
const TRIMESTERS = [{ label: "1st Trimester", weeks: "Weeks 1-12" }, { label: "2nd Trimester", weeks: "Weeks 13-26" }, { label: "3rd Trimester", weeks: "Weeks 27-40" }];

const FAQS = [
  { q: "How is the due date calculated?", a: "The most common method is Naegele's rule: add 280 days (40 weeks) to the first day of the last menstrual period (LMP). This assumes a 28-day menstrual cycle with ovulation on day 14. The formula: Due Date = LMP + 280 days (or +9 months +7 days). About 80% of babies are born within 2 weeks of this estimated date." },
  { q: "How accurate is the estimated due date?", a: "Only about 5% of babies are born on their exact due date. Most births occur within a window of 2 weeks before to 2 weeks after. Ultrasound dating (especially before 13 weeks) is highly accurate and may override the LMP-based estimate if dates differ by more than 5-7 days. The due date is a target, not a deadline." },
  { q: "What is gestational age vs. fetal age?", a: "Gestational age is counted from the first day of the last menstrual period - the standard medical convention. Fetal age (conception age) counts from actual fertilization, typically about 2 weeks after LMP. When your doctor says 'you're 8 weeks pregnant', they mean 8 weeks gestational age - the fetus is actually about 6 weeks old." },
  { q: "When do the trimesters begin and end?", a: "First trimester: weeks 1-12 - organ formation, highest miscarriage risk, nausea common. Second trimester: weeks 13-26 - rapid growth, movement begins, most comfortable period. Third trimester: weeks 27-40 - final development, lungs mature, preparation for birth. Each trimester brings distinct developmental milestones." },
  { q: "What is considered a full-term pregnancy?", a: "A full-term pregnancy is 39-40 weeks 6 days. Early term is 37-38 weeks 6 days. Late term is 41-41 weeks 6 days. Post-term is 42 weeks or beyond. Pre-term is before 37 weeks. Outcomes are generally best for babies born at full term or early term (37-40 weeks)." },
  { q: "Can my due date change after an ultrasound?", a: "Yes. If the ultrasound-measured fetal size differs significantly from the LMP-estimated date (by 5 days before 13 weeks, 7 days at 13-20 weeks, or 10-14 days after 20 weeks), doctors typically adjust the due date to match the ultrasound. First-trimester ultrasounds are the most accurate for dating." },
  { q: "What is the probability of going into labor at any given week?", a: "Natural labor rarely occurs before 37 weeks. The probability rises steadily from week 37: about 10% of births occur at 37 weeks, 20% at 38 weeks, 25% at 39 weeks, 25% at 40 weeks, and 20% at 41+ weeks. Only 5% reach 42 weeks without intervention." },
  { q: "What prenatal care appointments should I expect?", a: "Typical schedule: weeks 4-28 (every 4 weeks), weeks 28-36 (every 2 weeks), weeks 36-40 (weekly). Key visits include the first appointment (8-12 weeks for dating), anatomy scan (18-20 weeks), glucose test (24-28 weeks), Group B strep test (35-37 weeks), and weekly checks near term." },
];

const FETAL_MILESTONES = [
  ["Week 6", "Heartbeat detectable by ultrasound"],
  ["Week 10", "Fingers, toes, and all major organs formed"],
  ["Week 12", "End of 1st trimester, risk of miscarriage drops significantly"],
  ["Week 16", "Can often determine sex by ultrasound"],
  ["Week 18-20", "Anatomy scan - detailed structural assessment"],
  ["Week 22", "Viability threshold - survival possible with NICU support"],
  ["Week 24", "Lungs begin producing surfactant"],
  ["Week 28", "Eyes open for first time"],
  ["Week 32", "Rapid weight gain, most organs nearly mature"],
  ["Week 37", "Considered early term, can be safely delivered"],
  ["Week 39-40", "Full term - optimal developmental window"],
];

export default function DueDateCalculator() {
  const today = new Date();
  const [lmpStr, setLmpStr] = useState(new Date(today.getTime() - 60 * 24 * 3600000).toISOString().split("T")[0]);

  const lmp = new Date(lmpStr);
  const valid = !isNaN(lmp.getTime()) && lmp <= today;
  const dueDate = valid ? new Date(lmp.getTime() + 280 * 24 * 3600000) : null;
  const conceptionDate = valid ? new Date(lmp.getTime() + 14 * 24 * 3600000) : null;
  const gestWeeks = valid ? Math.floor((today.getTime() - lmp.getTime()) / (7 * 24 * 3600000)) : 0;
  const gestDays = valid ? Math.floor(((today.getTime() - lmp.getTime()) % (7 * 24 * 3600000)) / (24 * 3600000)) : 0;
  const daysLeft = dueDate ? Math.max(0, Math.ceil((dueDate.getTime() - today.getTime()) / (24 * 3600000))) : 0;
  const trimesterIdx = gestWeeks < 13 ? 0 : gestWeeks < 27 ? 1 : 2;
  const progressPct = Math.min(100, Math.round((gestWeeks / 40) * 100));

  const fmtDate = (d: Date) => `${MONTH_NAMES[d.getMonth()]} ${d.getDate()}, ${d.getFullYear()}`;

  return (
    <>
      <SEOHead
        title="Free Due Date Calculator Online - Calculate Your Baby Due Date Instantly | CalcHive"
        description="Free online due date calculator. Calculate your estimated due date and trimester from your last menstrual period instantly. 100% free for every mom, no signup required."
        canonical="/due-date-calculator"
        keywords="free due date calculator, baby due date calculator free online, pregnancy due date estimator free, calculate due date free, free trimester calculator"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Due Date Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free due date calculator to calculate due date free and estimate your pregnancy timeline from your last menstrual period. This baby due date calculator free online also works as a pregnancy due date estimator free and free trimester calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-8">
            <label htmlFor="lmp" className="text-sm font-semibold text-foreground block mb-2">First Day of Last Menstrual Period (LMP)</label>
            <input id="lmp" type="date" value={lmpStr} max={today.toISOString().split("T")[0]} onChange={e => setLmpStr(e.target.value)} className="w-full sm:w-auto px-4 py-2.5 rounded-xl border border-input bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
          </div>
          {dueDate && (
            <motion.div key={lmpStr} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
              <div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated Due Date</p>
                <p className="text-4xl font-black text-white tracking-tight" data-testid="result-due-date">{fmtDate(dueDate)}</p>
                <p className="text-white/70 text-sm mt-1">{daysLeft > 0 ? `${daysLeft} days to go` : "Past due date"}</p>
              </div>
              <div className="grid grid-cols-3 gap-3 mb-4">
                {[
                  { label: "Gestational Age", value: `${gestWeeks}w ${gestDays}d` },
                  { label: "Current Trimester", value: TRIMESTERS[trimesterIdx].label },
                  { label: "Conception Date", value: conceptionDate ? fmtDate(conceptionDate) : "" },
                ].map(({ label, value }) => (
                  <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                    <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                    <p className="text-sm font-extrabold text-foreground">{value}</p>
                  </div>
                ))}
              </div>
              <div className="mb-4">
                <div className="flex justify-between text-xs text-muted-foreground mb-1">
                  <span>Week 0</span>
                  <span className="font-semibold text-teal-600 dark:text-teal-400">Week {gestWeeks} of 40 ({progressPct}%)</span>
                  <span>Week 40</span>
                </div>
                <div className="h-3 bg-muted rounded-full overflow-hidden">
                  <div className="h-full bg-gradient-to-r from-teal-400 to-teal-600 rounded-full transition-all" style={{ width: `${progressPct}%` }} />
                </div>
              </div>
              <div className="flex gap-2 flex-wrap">
                {TRIMESTERS.map((t, i) => (
                  <div key={t.label} className={`flex-1 min-w-0 px-3 py-2 rounded-xl border text-center ${i === trimesterIdx ? "bg-primary/10 border-primary/30 text-primary" : "bg-muted/40 border-border text-muted-foreground"}`}>
                    <p className="text-xs font-bold">{t.label}</p>
                    <p className="text-xs opacity-80">{t.weeks}</p>
                  </div>
                ))}
              </div>
            </motion.div>
          )}
          {!valid && <p className="text-center text-muted-foreground py-4">Enter the first day of your last period to calculate your due date.</p>}
        </section>
        <MedicalDisclaimer variant="pregnancy" /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Due Date for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Naegele's rule, developed by German obstetrician Franz Karl Naegele in the early 1800s, remains the standard method for estimating due dates. It assumes a 28-day cycle with conception occurring on day 14. While newer ultrasound-based dating is more precise, Naegele's rule provides an excellent initial estimate.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Due Date = LMP + 280 days (40 weeks)</p>
            <p>Alternative: Due Date = LMP + 9 months + 7 days</p>
            <p>Conception Date - LMP + 14 days (assuming 28-day cycle)</p>
            <p className="text-xs text-muted-foreground mt-2">LMP = First day of last menstrual period</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Know Which Trimester You Are In</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Gestational Week", "Key Development Milestone"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {FETAL_MILESTONES.map(([week, milestone]) => (
                  <tr key={week} className={`hover:bg-muted/30 ${gestWeeks > 0 && week === `Week ${gestWeeks}` ? "bg-teal-50 dark:bg-teal-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-teal-600 dark:text-teal-400">{week}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{milestone}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Baby Due Date Tool for Every Mom</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Term", "Gestational Weeks", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Pre-term", "< 37 weeks", "Increased NICU risk, monitoring required"],
                  ["Early term", "37-38w 6d", "Lungs mostly developed, generally safe"],
                  ["Full term", "39-40w 6d", "Optimal development - best outcomes"],
                  ["Late term", "41-41w 6d", "Increased monitoring recommended"],
                  ["Post-term", "42+ weeks", "Induction typically recommended"],
                ].map(([term, weeks, notes]) => (
                  <tr key={term} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-teal-600 dark:text-teal-400">{term}</td>
                    <td className="py-2.5 px-4 font-mono text-foreground">{weeks}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/due-date-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


